const crypto = require('crypto');
const https = require('https');

const appId = $env.GITHUB_APP_ID;
const installationId = $env.GITHUB_INSTALLATION_ID;
const privateKeyBase64 = $env.GITHUB_PRIVATE_KEY_BASE64;
const privateKey = Buffer.from(privateKeyBase64, 'base64').toString('utf8');

const now = Math.floor(Date.now() / 1000);
const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
const payload = Buffer.from(JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId })).toString('base64url');
const signature = crypto.sign('SHA256', Buffer.from(`${header}.${payload}`), privateKey).toString('base64url');
const jwt = `${header}.${payload}.${signature}`;

const token = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.github.com',
    path: `/app/installations/${installationId}/access_tokens`,
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${jwt}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'Content-Length': 0
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => {
      if (res.statusCode !== 201) reject(new Error(`GitHub token request failed: ${res.statusCode} ${body}`));
      else resolve(JSON.parse(body).token);
    });
  });
  req.on('error', reject);
  req.end();
});

return [{ json: { ...$input.first().json, githubToken: token } }];

// Check if an agent container is already running.
// If so, exit — story stays status:ready for next pickup.
const { execSync } = require('child_process');

let running = '';
try {
  running = execSync(
    'docker ps --filter "label=apeiron-agent" --format "{{.ID}}"'
  ).toString().trim();
} catch (e) {
  // docker command failed — treat as not running
  running = '';
}

if (running) {
  return [{ json: {
    ...($input.first().json),
    blocked: true,
    reason: 'Agent container already running',
    runningContainerId: running
  }}];
}

return [{ json: { ...($input.first().json), blocked: false } }];

// Post comment that agent is busy, then exit.
// Story stays status:ready for next pickup.
const https = require('https');
const data = $input.first().json;
const token = data.githubToken;
const owner = data.body.repoOwner;
const repo = data.body.repoName;
const storyNumber = data.body.issueNumber;

const commentBody = JSON.stringify({
  body: `\u26a0\ufe0f Agent is currently busy with another story (container \`${data.runningContainerId}\`). This story will be picked up when the agent is available. Story remains \`status:ready\`.`
});

await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.github.com',
    path: `/repos/${owner}/${repo}/issues/${storyNumber}/comments`,
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(commentBody)
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => resolve());
  });
  req.on('error', reject);
  req.write(commentBody);
  req.end();
});

return [{ json: { action: 'agent-busy', storyNumber } }];

