  const depLabels = (depIssue.data.labels || []).map(l => l.name);
  const isClosed = depIssue.data.state === 'closed';
  const isInReview = depLabels.includes('status:in-review');
  if (!isClosed && !isInReview) {
    unsatisfied.push({ number: depNumber, labels: depLabels, state: depIssue.data.state });
  }
}

if (unsatisfied.length > 0) {
