  `-e OPENROUTER_MODEL=${openrouterModel}`,
  `-e GH_TOKEN=${token}`,
  `-e GT_TOKEN=${gtToken}`,
  'apeiron-agent:latest',
  '"opencode --prompt-file /prompt.md"'
].join(' ')).toString().trim();

