  storyNumber,
  githubToken: token,
  owner: data.owner,
  repo: data.repo
}}];

// Poll the agent container until it exits or times out.
const { execSync } = require('child_process');
const data = $input.first().json;
const containerId = data.containerId;
const maxWaitMinutes = 30;
const pollIntervalMs = 15000;
const maxPolls = (maxWaitMinutes * 60 * 1000) / pollIntervalMs;

for (let i = 0; i < maxPolls; i++) {
  let status;
  try {
    status = execSync(
      `docker inspect --format '{{.State.Status}}' ${containerId}`
    ).toString().trim();
  } catch (e) {
    // Container might have been removed externally
    return [{ json: {
      exitCode: -2,
      logs: `Container ${containerId} not found: ${e.message}`,
      storyNumber: data.storyNumber,
      githubToken: data.githubToken,
      owner: data.owner,
      repo: data.repo
    }}];
  }

  if (status === 'exited') {
    const exitCode = parseInt(execSync(
      `docker inspect --format '{{.State.ExitCode}}' ${containerId}`
    ).toString().trim(), 10);

    // Capture logs for debugging
    let logs = '';
    try {
      logs = execSync(
        `docker logs --tail 100 ${containerId}`
      ).toString();
    } catch (e) {
      logs = `(Failed to capture logs: ${e.message})`;
    }

    // Cleanup container
    try {
      execSync(`docker rm ${containerId}`);
    } catch (e) {
      // Best effort cleanup
    }

    return [{ json: {
      exitCode,
      logs,
      storyNumber: data.storyNumber,
      githubToken: data.githubToken,
      owner: data.owner,
      repo: data.repo
    }}];
  }

  await new Promise(r => setTimeout(r, pollIntervalMs));
}

// Timeout — kill the container
try {
  execSync(`docker kill ${containerId}`);
  execSync(`docker rm ${containerId}`);
} catch (e) {
  // Best effort
}

return [{ json: {
  exitCode: -1,
  logs: `Timed out after ${maxWaitMinutes} minutes`,
  storyNumber: data.storyNumber,
  githubToken: data.githubToken,
  owner: data.owner,
  repo: data.repo
}}];

