  await githubRest('DELETE', `/repos/${owner}/${repo}/issues/${storyNumber}/labels/status%3Ain-progress`);
} catch (e) { /* label might not exist */ }

await githubRest('POST', `/repos/${owner}/${repo}/issues/${storyNumber}/labels`, {
  labels: ['status:blocked']
});

// Truncate logs if too long for a comment (GitHub max comment is 65536 chars)
const maxLogLen = 3000;
const truncatedLogs = logs.length > maxLogLen
  ? logs.substring(logs.length - maxLogLen) + '\n... (truncated)'
  : logs;

// Post failure comment
await githubRest('POST', `/repos/${owner}/${repo}/issues/${storyNumber}/comments`, {
  body: `\u274c Agent failed to implement this story. Container exit code: \`${exitCode}\`. Story moved to \`status:blocked\`.\n\n<details>\n<summary>Container logs (last 100 lines)</summary>\n\n\`\`\`\n${truncatedLogs}\n\`\`\`\n\n</details>`
});

return [{ json: { action: 'failure', storyNumber, exitCode } }];
